/** @internal */
export const VALUE_GROUP_ID = 'strato-filter-field-value-suggestions';

/**
 * Returns an ordered array of value suggestion groups for a given filter key.
 * Preserves declaration order and threads group metadata (label, aria-label).
 *
 * Handles all code paths: early exits (no key, pasting, wildcards, search),
 * single predicates, function predicates, and the full grouped array pipeline.
 * @internal
 */
export function getValueSuggestionGroups(
  key: string | undefined,
  comparisonOperator: FilterFieldComparisonOperators | undefined,
  internalValidatorMap: InternalValidatorMap | undefined,
  currentToken: FilterFieldValueNode,
  showDefaultValueOrWildcardSuggestions: boolean,
  showWildcardValueSuggestions: boolean,
  isPasting?: boolean,
): SuggestionGroup<FilterFieldSuggestion>[] {
  if (
    !isPasting &&
    (!key || !internalValidatorMap) &&
    !showDefaultValueOrWildcardSuggestions &&
    !showWildcardValueSuggestions
  ) {
    if (
      comparisonOperator === 'search' &&
      (currentToken.textValue === '' || currentToken.textValue === '""')
    ) {
      return wrapSuggestionsInGroup(getStartTypingSuggestion('search phrase'));
    }

    return currentToken.textValue
      ? []
      : wrapSuggestionsInGroup(getStartTypingSuggestion('value'));
  }

  if (!isFilterFieldLeafNode(currentToken)) {
    return [];
  }

  if (showDefaultValueOrWildcardSuggestions) {
    return wrapSuggestionsInGroup(
      ...getDefaultValueOrWildcardSuggestion(
        currentToken.textValue,
        currentToken.value as string,
        internalValidatorMap,
        key,
        comparisonOperator,
      ),
    );
  }

  if (showWildcardValueSuggestions) {
    return wrapSuggestionsInGroup(
      ...getValueWildcardOperatorSuggestions(
        key,
        internalValidatorMap,
        !!comparisonOperator,
      ),
    );
  }

  if (!key || !internalValidatorMap) {
    return wrapSuggestionsInGroup(
      getDefaultValueSuggestion(currentToken.textValue),
    );
  }

  const predicate = internalValidatorMap.normalizedKeys.byKey.get(key);

  if (
    !predicate?.valuePredicate ||
    typeof predicate.valuePredicate === 'function'
  ) {
    return currentToken.textValue
      ? wrapSuggestionsInGroup(
          getDefaultValueSuggestion(currentToken.textValue),
        )
      : wrapSuggestionsInGroup(getStartTypingSuggestion('value'));
  }

  // The valuePredicate may hold a single item or a group config at this point.
  // Normalize into an array for unified processing in the suggestion groups pipeline below.
  const valuePredicateItems = Array.isArray(predicate.valuePredicate)
    ? predicate.valuePredicate
    : [predicate.valuePredicate];

  const groups: SuggestionGroup<FilterFieldSuggestion>[] = [];
  let pendingItems: FilterFieldSuggestion[] = [];

  /**
   * Push accumulated individual items into an implicit group.
   * Individual values are collected into an implicit group to preserve the correct
   * declaration order when mixing groups and individual values in the value predicate.
   */
  function processPendingItems() {
    if (pendingItems.length === 0) {
      return;
    }

    groups.push({
      id: `${VALUE_GROUP_ID}-implicit-${groups.length}`,
      suggestions: pendingItems,
    });

    pendingItems = [];
  }

  for (let index = 0; index < valuePredicateItems.length; index++) {
    const item = valuePredicateItems[index];

    if (isFilterFieldValueSuggestionGroupConfig(item)) {
      processPendingItems();

      const groupSuggestions: FilterFieldSuggestion[] = [];

      for (const suggestion of item.suggestions) {
        collectItem(
          getSuggestionFromValuePredicate(suggestion, currentToken.textValue),
          groupSuggestions,
        );
      }

      if (groupSuggestions.length > 0) {
        groups.push({
          id: resolveGroupId(item, `value-group-${index}`),
          label: item.label,
          'aria-label': item['aria-label'],
          suggestions: groupSuggestions,
        });
      }

      continue;
    }

    collectItem(
      getSuggestionFromValuePredicate(item, currentToken.textValue),
      pendingItems,
    );
  }

  processPendingItems();

  // Check whether any concrete suggestion matches the current text value.
  const suggestionMatchesTextValue = groups.some((group) =>
    group.suggestions.some(
      (suggestion) =>
        suggestion.suggestionType === 'validatorMap' &&
        suggestion.value === currentToken.textValue,
    ),
  );

  // Remove the generic hint when a concrete match exists or when there are
  // enough concrete suggestions.
  const result: SuggestionGroup<FilterFieldSuggestion>[] = [];

  for (const group of groups) {
    const suggestions =
      suggestionMatchesTextValue ||
      (!currentToken.textValue && group.suggestions.length > 1)
        ? group.suggestions.filter((s) => s.suggestionType === 'validatorMap')
        : group.suggestions;

    if (suggestions.length > 0) {
      result.push({ ...group, suggestions });
    }
  }

  return result;
}

function wrapSuggestionsInGroup(
  ...suggestions: FilterFieldSuggestion[]
): SuggestionGroup<FilterFieldSuggestion>[] {
  return suggestions.length > 0 ? [{ id: VALUE_GROUP_ID, suggestions }] : [];
}

/**
 * @internal
 */
export function getDefaultValueOrWildcardSuggestion(
  textValue: string,
  value: string,
  internalValidatorMap: InternalValidatorMap | undefined,
  keyValue: string | undefined,
  comparisonOperator: FilterFieldComparisonOperators | undefined,
) {
  const comparisonOperators = getValidOperators(keyValue, internalValidatorMap);
  const isValidOperator =
    comparisonOperator && comparisonOperators.includes(comparisonOperator);

  switch (comparisonOperator) {
    case 'starts-with':
      return isValidOperator
        ? [getStartsWithValueSuggestion(textValue, value)]
        : [getStartsWithIsNotSupportedSuggestion()];
    case 'ends-with':
      return isValidOperator
        ? [getEndsWithValueSuggestion(textValue, value)]
        : [getEndsWithIsNotSupportedSuggestion()];
    case 'contains':
      return isValidOperator
        ? [getContainsValueSuggestion(textValue, value)]
        : [getContainsIsNotSupportedSuggestion()];
    case 'not-starts-with':
      return isValidOperator
        ? [getNotStartsWithValueSuggestion(textValue, value)]
        : [getStartsWithIsNotSupportedSuggestion()];
    case 'not-ends-with':
      return isValidOperator
        ? [getNotEndsWithValueSuggestion(textValue, value)]
        : [getEndsWithIsNotSupportedSuggestion()];
    case 'not-contains':
      return isValidOperator
        ? [getNotContainsValueSuggestion(textValue, value)]
        : [getContainsIsNotSupportedSuggestion()];
    default: {
      if (textValue && typeof comparisonOperator !== 'boolean') {
        return [getDefaultValueSuggestion(textValue)];
      }
      return [getStartTypingSuggestion('value')];
    }
  }
}

function collectItem(
  result: FilterFieldSuggestion | FilterFieldSuggestion[] | undefined,
  suggestions: FilterFieldSuggestion[],
): void {
  if (result === undefined) {
    return;
  }

  if (Array.isArray(result)) {
    suggestions.push(...result);
    return;
  }

  suggestions.push(result);
}

function getSuggestionFromValuePredicate(
  predicate: FilterFieldValuePredicate,
  textValue?: string,
): FilterFieldSuggestion | FilterFieldSuggestion[] | undefined {
  const { suggestionType } = getValidValueTypes(predicate);
  const predicateValue = getPredicateValue(predicate);

  if (
    !Array.isArray(predicate) &&
    (typeof predicate !== 'object' ||
      isFilterFieldValidatorMapDurationSpecification(predicate) ||
      isFilterFieldRichValuePredicate(predicate))
  ) {
    const richPredicate = isFilterFieldRichValuePredicate(predicate)
      ? predicate
      : undefined;

    return {
      value: predicateValue,
      displayValue: richPredicate?.displayValue,
      details: richPredicate?.details,
      suggestionType: 'validatorMap',
      valueType: Array.isArray(suggestionType) ? 'JSONPath' : suggestionType,
    };
  }

  if (
    isFilterFieldValidatorMapTypeSpecification(predicate) &&
    predicate.type === 'Boolean'
  ) {
    return [
      { value: 'true', suggestionType: 'validatorMap', valueType: 'Boolean' },
      { value: 'false', suggestionType: 'validatorMap', valueType: 'Boolean' },
    ];
  }

  if (textValue) {
    return getDefaultValueSuggestion(
      textValue,
      Array.isArray(suggestionType) ? 'Any' : suggestionType,
    );
  } else {
    return getStartTypingSuggestion(
      'value',
      Array.isArray(suggestionType) ? 'Any' : suggestionType,
    );
  }
}

function getPredicateValue(predicate: FilterFieldValuePredicate) {
  if (Array.isArray(predicate)) {
    return '';
  }

  if (typeof predicate !== 'object') {
    return predicate.toString();
  }

  if (isFilterFieldRichValuePredicate(predicate)) {
    return `${predicate.value}`;
  }

  if (isFilterFieldValidatorMapDurationSpecification(predicate)) {
    return `${predicate.value}${predicate.unit}`;
  }

  return '';
}

function getValueWildcardOperatorSuggestions(
  key: string | undefined,
  internalValidatorMap: InternalValidatorMap | undefined,
  currentOperatorValue: boolean,
): FilterFieldSuggestion[] {
  const operators = getValidOperatorsShortForWildcardOperators(
    key,
    internalValidatorMap,
  );

  return operators
    .filter((operator) => {
      // if the statement is foo = * we want to show the matching wildcard operators (not the not-variants)
      if (currentOperatorValue) {
        return (
          operator === '= *' ||
          (!operator.includes('not') && operator !== '!= *')
        );
      }
      // if the statement is foo != * we want to show the matching wildcard operators (only the not-variants)
      return operator === '!= *' || operator.includes('not');
    })
    .map(
      (operator) =>
        operatorSuggestionsWithDetails[operator] ?? { value: operator },
    );
}

/**
 * Returns valid operator short names for wildcard operators
 */
function getValidOperatorsShortForWildcardOperators(
  key: string | undefined,
  internalValidatorMap: InternalValidatorMap | undefined,
) {
  const operators = getValidOperators(key, internalValidatorMap);
  const result: string[] = [];

  if (operators.includes('exists')) {
    result.push('= *');
  }
  if (operators.includes('not-exists')) {
    result.push('!= *');
  }
  if (operators.includes('contains')) {
    result.push('contains');
  }
  if (operators.includes('starts-with')) {
    result.push('starts-with');
  }
  if (operators.includes('ends-with')) {
    result.push('ends-with');
  }
  if (operators.includes('not-starts-with')) {
    result.push('not-starts-with');
  }
  if (operators.includes('not-contains')) {
    result.push('not-contains');
  }
  if (operators.includes('not-ends-with')) {
    result.push('not-ends-with');
  }

  return result;
}

function getDefaultValueSuggestion(
  value: string,
  valueType: FilterFieldPrimitive | string = 'Any',
): FilterFieldSuggestionProps {
  // Check if the value starts and ends with a quote.
  const match = /^"(.+)(?<!\\)"$/.exec(value);
  const textValue = match ? match[1] : value;

  return {
    trailing: ' ',
    value,
    valueType,
    suggestionType: 'hint-useAsValue',
    id: 'strato-filterfield-suggestion-use-as-value',
    displayValue: (
      <FormattedMessage
        {...filterFieldMessages.suggestions.useAsValue}
        values={{
          value: (
            <>
              &nbsp;<mark>{textValue}</mark>&nbsp;
            </>
          ),
        }}
      />
    ),
  };
}

function getStartsWithIsNotSupportedSuggestion(
  valueType: FilterFieldPrimitive = 'Any',
): FilterFieldSuggestionProps {
  return {
    trailing: '',
    valueType,
    suggestionType: 'hint-wildcard',
    id: 'strato-filterfield-suggestion-starts-with-not-supported',
    displayValue: (
      <FormattedMessage
        {...filterFieldMessages.unsupportedOperators.startsWith}
      />
    ),
  };
}

