function getStartsWithValueSuggestion(
  textValue: string,
  value: string,
  valueType: FilterFieldPrimitive = 'Any',
): FilterFieldSuggestionProps & {
  [key: `data-strato-filter-field-${string}`]: boolean;
} {
  return {
    trailing: ' ',
    value: textValue,
    valueType,
    suggestionType: 'hint-wildcard',
    id: 'strato-filterfield-suggestion-starts-with-value',
    displayValue: (
      <FormattedMessage
        {...filterFieldMessages.value.startsWith}
        values={{
          value: <mark>{value}</mark>,
        }}
      />
    ),
    escapeSuggestion: false,
  };
}

